static const uint8_t* const OUTFITS_INK[] = {
  OUTFIT_0_INK, OUTFIT_1_INK, OUTFIT_2_INK, OUTFIT_3_INK, OUTFIT_4_INK, OUTFIT_5_INK
};
static const uint8_t* const OUTFITS_SKIN[] = {
  OUTFIT_0_SKIN, OUTFIT_1_SKIN, OUTFIT_2_SKIN, OUTFIT_3_SKIN, OUTFIT_4_SKIN, OUTFIT_5_SKIN
};

// Returns outfit index (0-5) for a temperature in Fahrenheit
static inline uint8_t outfit_index(float tempF) {
  if (tempF >= 78.8f) return 0;
  if (tempF >= 69.8f) return 1;
  if (tempF >= 59.0f) return 2;
  if (tempF >= 50.0f) return 3;
  if (tempF >= 39.2f) return 4;
  return 5;
}

// Draw the correct outfit for a temperature (Fahrenheit).
// Does NOT clear the background — caller is responsible for that.
// skinColor: body/skin tone (default white). inkColor: outlines/clothing (default black).
// Call after canvas_begin().
static inline void draw_outfit_for_temp(Arduino_GFX* gfx, float tempF, int16_t x = 0, int16_t y = 0, uint16_t skinColor = 0xFFFF, uint16_t inkColor = 0x0000) {
  uint8_t idx = outfit_index(tempF);
  gfx->drawBitmap(x, y, (const uint8_t*)pgm_read_ptr(&OUTFITS_SKIN[idx]), OUTFIT_W, OUTFIT_H, skinColor);
  gfx->drawBitmap(x, y, (const uint8_t*)pgm_read_ptr(&OUTFITS_INK[idx]), OUTFIT_W, OUTFIT_H, inkColor);
}
